def get_city_history(city_name):
    city_data = {
        'Balasagun': {
            'location': 'Kyrgyzstan, Chüy Valley',
            'founding_empire': 'Kara-Khanid Khanate',
            'key_dates': {
                'capital': '10th century',
                'captured_by_Qara_Khitai': 1134,
                'captured_by_Mongols': 1218
            },
            'unesco_status': 'Silk Roads: Chang’an-Tianshan Corridor (2014)',
            'notable_figures': ['Yūsuf Balasaguni'],
            'modern_status': 'Village with ruins'
        }
    }
    return city_data.get(city_name, {})

# Example usage:
print(get_city_history('Balasagun'))

This function returns structured historical data for a given city, with Balasagun as a test case.
